<template><div><el-card><div class="page-title">{{isOut?'借出管理':'借入管理'}}</div><div class="toolbar"><el-input v-model="query.borrowNo" placeholder="借用单号" clearable style="width:180px"/><el-input v-model="query.partnerName" placeholder="往来单位" clearable style="width:160px"/><el-select v-model="query.warehouseId" placeholder="仓库" clearable style="width:160px"><el-option v-for="w in warehouses" :key="w.value" :label="w.label" :value="w.value"/></el-select><el-select v-model="query.status" placeholder="状态" clearable style="width:140px"><el-option v-for="s in statuses" :key="s.value" :label="s.label" :value="s.value"/></el-select><el-checkbox v-model="query.overdueOnly">只看逾期</el-checkbox><el-button type="primary" @click="fetchData">查询</el-button><el-button type="success" @click="router.push(`${basePath}/new`)">新增{{isOut?'借出':'借入'}}</el-button></div></el-card><el-card class="table-card"><el-table :data="tableData" v-loading="loading" border stripe><el-table-column prop="borrowNo" label="单号" width="180"/><el-table-column prop="borrowDate" label="借用日期" width="115"/><el-table-column prop="expectedReturnDate" label="预计归还" width="115"><template #default="{row}"><span :class="{overdue:row.overdue}">{{row.expectedReturnDate||'-'}}</span></template></el-table-column><el-table-column prop="warehouseName" label="仓库" min-width="130"/><el-table-column prop="partnerName" label="往来单位" min-width="150"/><el-table-column prop="totalQuantity" label="总数量" width="100" align="right"/><el-table-column label="状态" width="150"><template #default="{row}"><el-tag :type="statusType(row.status)" size="small">{{statusLabel(row.status)}}</el-tag><el-tag v-if="row.overdue" type="danger" size="small" class="overdue-tag">逾期</el-tag></template></el-table-column><el-table-column label="操作" width="275" fixed="right"><template #default="{row}"><el-button size="small" @click="router.push(`${basePath}/${row.id}`)">查看</el-button><el-button v-if="row.status==='DRAFT'" size="small" type="success" @click="approve(row)">审核生效</el-button><el-button v-if="['APPROVED','PARTIALLY_RETURNED'].includes(row.status)" size="small" type="primary" @click="router.push(`${basePath}/${row.id}?return=1`)">归还</el-button><el-button v-if="row.status==='DRAFT'" size="small" type="danger" @click="cancel(row)">取消</el-button><el-button v-if="['DRAFT','CANCELLED'].includes(row.status)" size="small" type="danger" plain @click="remove(row)">删除</el-button></template></el-table-column></el-table><el-pagination class="pagination" background layout="total,prev,pager,next" :total="total" v-model:current-page="query.page" v-model:page-size="query.size" @change="fetchData"/></el-card></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref,watch}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{approveInventoryBorrow,cancelInventoryBorrow,deleteInventoryBorrow,getInventoryBorrows}from'@/api/inventory';import{getWarehouseOptions}from'@/api/masterdata';const route=useRoute(),router=useRouter(),type=computed(()=>String(route.meta.borrowType||'BORROW_OUT')),isOut=computed(()=>type.value==='BORROW_OUT'),basePath=computed(()=>isOut.value?'/inventory/borrow-outs':'/inventory/borrow-ins'),loading=ref(false),tableData=ref<any[]>([]),total=ref(0),warehouses=ref<any[]>([]),query=reactive<any>({page:1,size:10,borrowNo:'',partnerName:'',warehouseId:'',status:'',overdueOnly:false}),statuses=[{label:'草稿',value:'DRAFT'},{label:'借用中',value:'APPROVED'},{label:'部分归还',value:'PARTIALLY_RETURNED'},{label:'已归还',value:'COMPLETED'},{label:'已取消',value:'CANCELLED'}];onMounted(async()=>{warehouses.value=(await getWarehouseOptions()).data||[];fetchData()});watch(type,()=>{query.page=1;fetchData()});function statusLabel(v:string){return statuses.find(i=>i.value===v)?.label||v}function statusType(v:string){return({DRAFT:'info',APPROVED:'warning',PARTIALLY_RETURNED:'primary',COMPLETED:'success',CANCELLED:'danger'}as any)[v]||''}async function fetchData(){loading.value=true;try{const r=await getInventoryBorrows({...query,borrowType:type.value});tableData.value=r.data.records||[];total.value=r.data.total||0}finally{loading.value=false}}async function approve(row:any){await ElMessageBox.confirm(`审核后将${isOut.value?'减少':'增加'}仓库库存，是否继续？`,'审核借用单',{type:'warning'});await approveInventoryBorrow(row.id);ElMessage.success('借用单已生效');fetchData()}async function cancel(row:any){await ElMessageBox.confirm('确定取消该借用单吗？','取消借用单',{type:'warning'});await cancelInventoryBorrow(row.id);ElMessage.success('借用单已取消');fetchData()}async function remove(row:any){await ElMessageBox.confirm('删除后无法恢复，是否继续？','删除借用单',{type:'warning'});await deleteInventoryBorrow(row.id);ElMessage.success('借用单已删除');fetchData()}</script>
<style scoped>.page-title{font-size:18px;font-weight:600;margin-bottom:12px}.toolbar{display:flex;gap:10px;align-items:center;flex-wrap:wrap}.table-card{margin-top:12px}.pagination{margin-top:12px;justify-content:flex-end}.overdue{color:#f56c6c;font-weight:600}.overdue-tag{margin-left:4px}</style>
